// MARK: - Rate Limiter

final class DeepLinkRateLimiter {
    static let shared = DeepLinkRateLimiter()
    
    private let maxRequestsPerMinute: Int = 10
    private var timestamps: [Date] = []
    private let lock = NSLock()
    
    private init() {}
    
    func allowRequest() -> Bool {
        lock.lock()
        defer { lock.unlock() }
        
        let now = Date()
        let oneMinuteAgo = now.addingTimeInterval(-60)
        
        // Remove timestamps older than 1 minute
        timestamps.removeAll { $0 < oneMinuteAgo }
        
        guard timestamps.count < maxRequestsPerMinute else {
            return false
        }
        
        timestamps.append(now)
        return true
    }
}

